import{_ as e,o as t,c as r,aQ as o}from"./chunks/framework.cDvftfeu.js";const m=JSON.parse('{"title":"概要","description":"Hamについて、セキュリティ、プライバシー、オープンソースの状況。","frontmatter":{"description":"Hamについて、セキュリティ、プライバシー、オープンソースの状況。"},"headers":[],"relativePath":"ja/about/index.md","filePath":"ja/about/index.md","lastUpdated":1777525243000}'),i={name:"ja/about/index.md"};function n(s,a,d,h,l,p){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h1><h3 id="hamは安全ですか" tabindex="-1">Hamは安全ですか？ <a class="header-anchor" href="#hamは安全ですか" aria-label="Permalink to &quot;Hamは安全ですか？&quot;">​</a></h3><p>Hamは、学籍番号やパスワードを第三者サーバーへ送信して認証することはありません。アカウント情報は端末内にのみ保存され、端末は大学のサーバーへ直接アクセスします。</p><p>一部の機能（成績分布など）ではバックエンドが必要です。データ送信が必要な場合は必ず同意を得て行い、重要な識別情報（学籍番号など）は送信前にハッシュ化します。これにより、運営側が個人を特定することはできません。</p><h3 id="なぜ今はオープンソースではないのですか" tabindex="-1">なぜ今はオープンソースではないのですか？ <a class="header-anchor" href="#なぜ今はオープンソースではないのですか" aria-label="Permalink to &quot;なぜ今はオープンソースではないのですか？&quot;">​</a></h3><p>プロジェクトにはプッシュサービスやApple開発者アカウントなどの機密情報が含まれているため、現時点では公開していません。ただし、Hamは完全に無料です。</p><p>ご意見は <a href="https://github.com/whu-ham/whu-ham.github.io/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> での交流や技術ディスカッションでお待ちしています。</p>',7)])])}const _=e(i,[["render",n]]);export{m as __pageData,_ as default};
